// 1) Забираем items из "Сбор текстов в 1"
let sourceItems = [];
try {
  if (typeof $items === 'function') {
    sourceItems = $items("Сбор текстов в 1", 0, 0) || [];
  } else if ($ && typeof $ === 'function' && $("Сбор текстов в 1")) {
    sourceItems = $("Сбор текстов в 1").items || [];
  } else {
    sourceItems = $input.all();
  }
} catch (e) {
  sourceItems = [];
}

// 2) Собираем тексты
const texts = [];
const pushIfString = (v) => { if (typeof v === 'string' && v.trim()) texts.push(v); };

for (const it of sourceItems) {
  const json = (it && it.json) ? it.json : it;

  pushIfString(json?.text_statei);

  if (Array.isArray(json?.text_statei)) {
    for (const el of json.text_statei) pushIfString(el);
  }

  // подхватываем ключи вида text_statei[0], text_statei[1] ...
  for (const k in json) {
    if (!Object.prototype.hasOwnProperty.call(json, k)) continue;
    if (/^text_statei(\[\d+\])?$/i.test(k)) {
      const v = json[k];
      if (Array.isArray(v)) v.forEach(pushIfString);
      else pushIfString(v);
    }
  }
}

// 3) Подсчёт слов
const countWords = (s) => {
  if (!s || typeof s !== 'string') return 0;
  const cleaned = s
    .replace(/https?:\/\/\S+/g, ' ')
    .replace(/[#*_`>]/g, ' ');
  const m = cleaned.match(/[A-Za-zА-Яа-яЁё0-9]+(?:['’\-][A-Za-zА-Яа-яЁё0-9]+)*/g);
  return m ? m.length : 0;
};

const perTextWords = texts.map(t => countWords(t));
const nonemptyCount = perTextWords.filter(n => n > 0).length;
const totalWords = perTextWords.reduce((a, b) => a + b, 0);
const averageWords = nonemptyCount ? Math.round(totalWords / nonemptyCount) : 0;

// 4) Markdown-слияние
const mergedMarkdown = texts.map((t, i) =>
  `## Текст конкурента ${i + 1}\n\n${t.trim()}`
).join('\n\n---\n\n');

// 5) Один айтем с ВСЕМИ полями
return [
  {
    json: {
      ems: averageWords,           // "объём слов" как среднее (можешь переименовать)
      text_count: texts.length,
      nonempty_count: nonemptyCount,
      total_words: totalWords,
      average_words: averageWords,
      per_text_words: perTextWords,
      merged_markdown: mergedMarkdown
    }
  }
];

